-- FSI_DEMO_DB.PAYMENTS.CHARGEBACKS

CREATE OR REPLACE TABLE FSI_DEMO_DB.PAYMENTS.CHARGEBACKS (

    CHARGEBACK_ID VARCHAR(20) NOT NULL,
    TRANSACTION_ID VARCHAR(30),
    MERCHANT_ID VARCHAR(20),
    CHARGEBACK_DATE DATE,
    ORIGINAL_TRANSACTION_DATE DATE,
    AMOUNT NUMBER(18,2),
    REASON_CODE VARCHAR(20),
    REASON_DESCRIPTION VARCHAR(200),
    STATUS VARCHAR(30),
    REPRESENTMENT_DATE DATE,
    REPRESENTMENT_OUTCOME VARCHAR(30),
    EVIDENCE_SUBMITTED BOOLEAN DEFAULT FALSE,
    CUSTOMER_DISPUTED BOOLEAN,
    MERCHANT_RESPONSE VARCHAR(16777216),
    RESOLUTION_DATE DATE,
    FINAL_OUTCOME VARCHAR(30),
    CREATED_AT TIMESTAMP_NTZ(9) DEFAULT CURRENT_TIMESTAMP(),
    PRIMARY KEY (CHARGEBACK_ID)

);


